#include <iostream>
#include <sstream>
#include <string>
#include <iomanip>

int main() {
    Calculator calc;
    std::string line;
    while (std::getline(std::cin, line)) {
        std::stringstream ss(line);
        std::string type_str;
        ss >> type_str;

        if (type_str == "int") {
            int a, b;
            ss >> a >> b;
            std::cout << calc.add(a, b) << std::endl;
        } else if (type_str == "double") {
            double a, b;
            ss >> a >> b;
            std::cout << std::fixed << std::setprecision(6) << calc.add(a, b) << std::endl;
        } else if (type_str == "float") {
            float a, b;
            ss >> a >> b;
            std::cout << std::fixed << std::setprecision(6) << calc.add(a, b) << std::endl;
        }
    }
    return 0;
}
